import React, { useEffect, useMemo, useRef, useState } from 'react';
import * as adminServiceModule from '../../services/adminService';

const adminService = (adminServiceModule as any).default || adminServiceModule;

const DEFAULT_PAGE_SIZE = 50;
const ADMIN_ORDERS_CACHE_KEY = 'admin_orders_cache_v3';
const ORDERS_REQUEST_TIMEOUT_MS = 30000;
const ORDERS_SOFT_LOADING_TIMEOUT_MS = 2500;

const readCachedOrders = () => {
    try {
        const raw = localStorage.getItem(ADMIN_ORDERS_CACHE_KEY);
        if (!raw) {
            return null;
        }

        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') {
            return null;
        }

        const rows = Array.isArray(parsed.orders) ? parsed.orders : [];

        return {
            orders: rows,
            totalOrders: Number(parsed.totalOrders || rows.length || 0),
            lastPage: Number(parsed.lastPage || 1),
        };
    } catch {
        return null;
    }
};

export default function AdminOrders() {
    const cachedOrders = readCachedOrders();

    const [orders, setOrders] = useState(cachedOrders?.orders || []);
    const [loading, setLoading] = useState(!(cachedOrders?.orders?.length > 0));
    const [error, setError] = useState('');

    const [serverPage, setServerPage] = useState(1);
    const [totalOrders, setTotalOrders] = useState(cachedOrders?.totalOrders || 0);
    const [lastPage, setLastPage] = useState(cachedOrders?.lastPage || 1);

    const cachedStatus = (() => {
        try {
            return localStorage.getItem('admin_orders_status_filter') || '';
        } catch {
            return '';
        }
    })();
    const cachedQuery = (() => {
        try {
            return localStorage.getItem('admin_orders_query_filter') || '';
        } catch {
            return '';
        }
    })();

    const [statusFilter, setStatusFilter] = useState(cachedStatus);
    const [query, setQuery] = useState(cachedQuery);

    const [statusDraft, setStatusDraft] = useState(cachedStatus);
    const [queryDraft, setQueryDraft] = useState(cachedQuery);

    const [trackingDrafts, setTrackingDrafts] = useState({});
    const requestIdRef = useRef(0);
    const foregroundRequestsRef = useRef(0);
    const retryTimerRef = useRef<number | null>(null);
    const retryAttemptRef = useRef(0);

    useEffect(() => {
        loadOrders(serverPage);

        return () => {
            requestIdRef.current += 1;
            if (retryTimerRef.current !== null) {
                window.clearTimeout(retryTimerRef.current);
                retryTimerRef.current = null;
            }
        };
    }, [serverPage, statusFilter, query]);

    useEffect(() => {
        const intervalId = window.setInterval(() => {
            loadOrders(serverPage, { silent: true });
        }, 25000);

        return () => {
            window.clearInterval(intervalId);
        };
    }, [serverPage, statusFilter, query]);

    const loadOrders = async (pageToLoad = 1, { silent = false } = {}) => {
        requestIdRef.current += 1;
        const requestId = requestIdRef.current;

        // Don't show loading - render with cache immediately
        try {
            const res = await Promise.race([
                adminService.getAllOrders({
                    timeout: 5000,
                    params: {
                        page: pageToLoad,
                        per_page: DEFAULT_PAGE_SIZE,
                        include_items: false,
                        include_users: false,
                        status: statusFilter || undefined,
                        q: query || undefined,
                    },
                }),
                new Promise<any>((resolve) => setTimeout(() => resolve(null), 2500)),
            ]);

            if (requestIdRef.current !== requestId || !res) {
                return;
            }

            const payload = res?.data?.data || {};
            const rows = Array.isArray(payload?.data) ? payload.data : [];
            const page = Number(payload?.current_page || pageToLoad || 1);
            const perPage = Number(payload?.per_page || DEFAULT_PAGE_SIZE);
            const total = Number(payload?.total || 0);
            const computedLastPage = Number(payload?.last_page || Math.max(1, Math.ceil(total / Math.max(1, perPage))));

            setOrders(rows);
            setTotalOrders(Number.isFinite(total) ? total : 0);
            setLastPage(Number.isFinite(computedLastPage) ? Math.max(1, computedLastPage) : 1);

            if (page !== serverPage) {
                setServerPage(page);
            }

            setTrackingDrafts((previous) => {
                const next = { ...previous };
                rows.forEach((order) => {
                    next[order.id] = order.tracking_number || previous[order.id] || '';
                });
                return next;
            });

            localStorage.setItem(ADMIN_ORDERS_CACHE_KEY, JSON.stringify({
                orders: rows,
                totalOrders: Number.isFinite(total) ? total : rows.length,
                lastPage: Number.isFinite(computedLastPage) ? Math.max(1, computedLastPage) : 1,
            }));
        } catch {
            // Silently fail - keep showing cached data
        }
    };

    const reloadCurrentPage = () => {
        loadOrders(serverPage);
    };

    const applyFilters = () => {
        const nextStatus = statusDraft;
        const nextQuery = queryDraft.trim();

        setStatusFilter(nextStatus);
        setQuery(nextQuery);
        setServerPage(1);

        // Save filters to localStorage
        localStorage.setItem('admin_orders_status_filter', nextStatus);
        localStorage.setItem('admin_orders_query_filter', nextQuery);
    };

    const resetFilters = () => {
        setStatusDraft('');
        setQueryDraft('');
        setStatusFilter('');
        setQuery('');
        setServerPage(1);

        // Clear filters from localStorage
        localStorage.removeItem('admin_orders_status_filter');
        localStorage.removeItem('admin_orders_query_filter');
    };

    const handleStatusChange = async (orderId, newStatus) => {
        try {
            await adminService.updateOrderStatus(orderId, newStatus, trackingDrafts[orderId] || '');
            reloadCurrentPage();
        } catch (err: any) {
            const errorMsg = err?.response?.data?.message || err?.message || 'Failed to update order status';
            console.error('Status update error:', err);
            setError(errorMsg);
        }
    };

    const handleSaveTracking = async (orderId) => {
        const current = orders.find((item) => item.id === orderId);
        if (!current) {
            return;
        }

        try {
            await adminService.updateOrderStatus(orderId, current.status, trackingDrafts[orderId] || '');
            reloadCurrentPage();
        } catch (err: any) {
            const errorMsg = err?.response?.data?.message || err?.message || 'Failed to save tracking number';
            console.error('Tracking save error:', err);
            setError(errorMsg);
        }
    };

    const handleConfirmDelivered = async (orderId) => {
        try {
            await adminService.updateOrderStatus(orderId, 'delivered', trackingDrafts[orderId] || '');
            reloadCurrentPage();
        } catch (err: any) {
            const errorMsg = err?.response?.data?.message || err?.message || 'Failed to confirm delivery';
            console.error('Delivery confirmation error:', err);
            setError(errorMsg);
        }
    };

    const formatAmount = (value) => `₱${parseFloat(value || 0).toFixed(2)}`;

    const summaryCards = useMemo(() => {
        const pageOrders = orders.length;
        const processingOrders = orders.filter((order) => order.status === 'processing').length;
        const shippedOrders = orders.filter((order) => order.status === 'shipped').length;
        const deliveredOrders = orders.filter((order) => order.status === 'delivered').length;

        return [
            { label: 'Matching Orders', value: totalOrders, accent: 'blue' },
            { label: 'This Page', value: pageOrders, accent: 'slate' },
            { label: 'Processing', value: processingOrders, accent: 'amber' },
            { label: 'Shipped', value: shippedOrders, accent: 'indigo' },
            { label: 'Delivered', value: deliveredOrders, accent: 'green' },
        ];
    }, [orders, totalOrders]);

    const exportOrders = () => {
        const csvRows = [
            ['Order ID', 'Customer', 'Parts', 'Purchased At', 'Delivered At', 'Tracking Number', 'Total', 'Status', 'Payment'],
            ...orders.map((order) => [
                order.order_number || '',
                order.user?.name || '',
                (order.items || [])
                    .map((item) => item.product?.name || item.name || 'Part')
                    .join(', '),
                order.created_at ? new Date(order.created_at).toLocaleString() : '',
                order.delivered_at ? new Date(order.delivered_at).toLocaleString() : '',
                order.tracking_number || '',
                Number(order.total_amount || 0).toFixed(2),
                order.status || '',
                order.payment_status || '',
            ]),
        ];

        const csv = csvRows.map((row) => row.map((cell) => `"${String(cell).replace(/"/g, '""')}"`).join(',')).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const anchor = document.createElement('a');
        anchor.href = url;
        anchor.download = 'carvex-orders-page.csv';
        anchor.click();
        URL.revokeObjectURL(url);
    };

    const startRow = totalOrders === 0 ? 0 : ((serverPage - 1) * DEFAULT_PAGE_SIZE) + 1;
    const endRow = Math.min(totalOrders, serverPage * DEFAULT_PAGE_SIZE);

    return (
        <div className="admin-page-content admin-orders">
            <div className="order-header-row">
                <div>
                    <h2>Order Management</h2>
                    <p>Track and manage customer orders</p>
                </div>

                <button type="button" className="btn btn-outline order-export-btn" onClick={exportOrders}>
                    Export Current Page
                </button>
            </div>

            <section className="order-summary-grid">
                {summaryCards.map((card) => (
                    <article className={`order-summary-card order-summary-card--${card.accent}`} key={card.label}>
                        <span className="summary-accent" />
                        <div>
                            <p>{card.label}</p>
                            <strong>{card.value}</strong>
                        </div>
                    </article>
                ))}
            </section>

            <div className="orders-panel">
                {error && <div className="alert alert-danger">{error}</div>}

                {error && (
                    <div style={{ marginBottom: '0.75rem' }}>
                        <button type="button" className="btn btn-outline btn-sm" onClick={reloadCurrentPage}>
                            Retry Orders
                        </button>
                    </div>
                )}

                <div className="orders-toolbar">
                    <div className="orders-search">
                        <input
                            type="text"
                            placeholder="Search by order ID or tracking notes..."
                            value={queryDraft}
                            onChange={(e) => setQueryDraft(e.target.value)}
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                    applyFilters();
                                }
                            }}
                        />
                    </div>
                    <div className="orders-filter" style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                        <select
                            value={statusDraft}
                            onChange={(e) => setStatusDraft(e.target.value)}
                            className="form-control"
                        >
                            <option value="">All Statuses</option>
                            <option value="pending">Pending</option>
                            <option value="processing">Processing</option>
                            <option value="shipped">Shipped</option>
                            <option value="delivered">Delivered</option>
                            <option value="cancelled">Cancelled</option>
                        </select>

                        <button type="button" className="btn btn-primary btn-sm" onClick={applyFilters}>
                            Apply
                        </button>
                        <button type="button" className="btn btn-outline btn-sm" onClick={resetFilters}>
                            Reset
                        </button>
                    </div>
                </div>

                <div className="orders-table">
                    <table>
                        <thead>
                            <tr>
                                <th>Order ID</th>
                                <th>Customer</th>
                                <th>Items</th>
                                <th>Total</th>
                                <th>Status</th>
                                <th>Tracking</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {orders.length > 0 ? orders.map((order) => {
                                const itemCount = Array.isArray(order.items) ? order.items.length : 0;

                                return (
                                    <tr key={order.id}>
                                        <td className="order-id">{order.order_number}</td>
                                        <td>{order.user?.name || '-'}</td>
                                        <td className="order-parts">{itemCount > 0 ? `${itemCount}` : '-'}</td>
                                        <td className="order-total">{formatAmount(order.total_amount)}</td>
                                        <td>
                                            <span className={`order-status-badge order-status-badge--${order.status}`}>
                                                {order.status}
                                            </span>
                                        </td>
                                        <td>
                                            <input
                                                type="text"
                                                value={trackingDrafts[order.id] || ''}
                                                onChange={(e) => setTrackingDrafts((prev) => ({ ...prev, [order.id]: e.target.value }))}
                                                placeholder="Tracking #"
                                                className="form-control"
                                                style={{ minWidth: '110px', fontSize: '0.9rem' }}
                                            />
                                        </td>
                                        <td className="actions">
                                            <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                                                <select
                                                    value={order.status}
                                                    onChange={(e) => handleStatusChange(order.id, e.target.value)}
                                                    className="status-select status-select--sm"
                                                    title="Change status and save"
                                                >
                                                    <option value="pending">Pending</option>
                                                    <option value="processing">Processing</option>
                                                    <option value="shipped">Shipped</option>
                                                    <option value="delivered">Delivered</option>
                                                    <option value="cancelled">Cancelled</option>
                                                </select>

                                                <button
                                                    type="button"
                                                    className="btn btn-outline btn-xs"
                                                    onClick={() => handleSaveTracking(order.id)}
                                                    title="Save tracking number"
                                                >
                                                    Save
                                                </button>

                                                {order.status !== 'delivered' && order.status !== 'cancelled' && (
                                                    <button
                                                        type="button"
                                                        className="btn btn-primary btn-xs"
                                                        onClick={() => handleConfirmDelivered(order.id)}
                                                        title="Mark as delivered"
                                                    >
                                                        ✓
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            }) : (
                                <tr>
                                    <td colSpan={7} className="orders-empty-state">
                                        {loading ? 'Please wait...' : 'No orders found for the selected filters.'}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>



                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.9rem', gap: '0.75rem', flexWrap: 'wrap' }}>
                    <div>
                        Showing {startRow}-{endRow} of {totalOrders}
                    </div>
                    <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                        <button
                            type="button"
                            className="btn btn-outline btn-sm"
                            disabled={loading || serverPage <= 1}
                            onClick={() => setServerPage((prev) => Math.max(1, prev - 1))}
                        >
                            Previous
                        </button>
                        <span>Page {serverPage} of {lastPage}</span>
                        <button
                            type="button"
                            className="btn btn-outline btn-sm"
                            disabled={loading || serverPage >= lastPage}
                            onClick={() => setServerPage((prev) => Math.min(lastPage, prev + 1))}
                        >
                            Next
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}
